    public function run(): void
    {
        // Map tour types & categories by slug for reliable lookup
        $types = TourType::pluck('id', 'slug');
        $cats  = Category::pluck('id', 'slug');

        $safaris = $this->getSafariData($types, $cats);

        foreach ($safaris as $data) {
            SafariPackage::updateOrCreate(
                ['slug' => $data['slug']],
                $data,
            );
        }

        $this->command->info('Seeded ' . count($safaris) . ' premium safari packages with multilingual content.');
    }

